const content = $json.text || '';
const jsonMatch = content.match(/\{[\s\S]*\}/);
let params = {};
try { params = JSON.parse(jsonMatch ? jsonMatch[0] : '{}'); } catch(e) {}

const userText = $('Input_Clean').first().json.text.toLowerCase();
let q = params.query || '';

if (userText.includes('cardio')) q = 'cardiologia';
else if (userText.includes('pediat')) q = 'pediatria';
else if (userText.includes('derma')) q = 'dermatologia';
else if (userText.includes('odont')) q = 'odontologia';
else if (userText.includes('segu') || userText.includes('osde')) q = 'seguros';

if (!q) q = $('Input_Clean').first().json.text;

return [{ json: {
  query: q,
  service_name: q,
  provider_id: 1,
  limit: 5,
  similarity_threshold: 0.05
} }];

// Analyze Resolve — Decidir estrategia RAG (SEC02)
const resolve = $input.first()?.json.data || {};
const userText = $('Input_Clean').first().json.text;
const parseData = $('Parse: get_services').first()?.json || {};

// Si el match es débil o no encontrado, buscar en RAG sin filtro de service_id
const useFilter = resolve.resolved && resolve.match_type !== 'WEAK';

return [{
  json: {
    query: resolve.resolved ? resolve.service_name : (parseData.query || userText),
    provider_id: resolve.provider_id || 1,
    service_id: useFilter ? resolve.service_id : null,
    limit: 5,
    similarity_threshold: 0.05,
    sql_context: {
      resolved: resolve.resolved,
      match_type: resolve.match_type,
      service_name: resolve.service_name,
      price: resolve.price,
      currency: resolve.currency || 'USD',
      candidates: resolve.candidates || []
    }
  }
}];

const nodes = ['Gen: create_booking', 'Gen: cancel_booking', 'Gen: check_availability', 'Gen: find_next', 'Gen: get_services', 'Fallback Gen'];

for (const name of nodes) {
  try {
    if ($(name).isExecuted) {
      const out = $(name).first().json;
      if (out.success === false) throw out; // Redirigir errores al handler central
      return [{ json: out }];
    }
  } catch (e) {
    if (e.success === false) throw e;
  }
}

throw { success: false, error_code: 'NO_BRANCH_EXECUTED', error_message: 'Ninguna rama se ejecutó correctamente.' };

const input = $input.first()?.json || {};
const error = $input.params.error || {}; // Si viene de un onError

const success = input.success !== false && !error.message;
const errorCode = error.code || input.error_code || 'EXECUTION_ERROR';
const errorMessage = error.message || input.error_message || 'Error desconocido';

return [{
  json: {
    success: false,
    error_code: errorCode,
    error_message: errorMessage,
    data: null,
    _meta: {
      source: 'NN_03-B_Pipeline_Agent',
      timestamp: new Date().toISOString(),
      version: '2.1.0'
    }
  }
}];

const input = $input.first()?.json || {};
let aiResp = input.text || input.output || input.ai_response || '';
if (typeof aiResp === 'string') aiResp = aiResp.replace(/^[\"']|[\"']$/g, '').trim();
if (!aiResp) aiResp = 'Lo siento, no pude procesar tu solicitud.';

let chatId = 0;
let intent = 'general_chat';

try { if ($('Input_Clean').isExecuted) chatId = $('Input_Clean').first().json.chat_id || 0; } catch(e) {}
try { if ($('Intent Normalizer').isExecuted) intent = $('Intent Normalizer').first().json.intent || 'general_chat'; } catch(e) {}

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      intent,
      chat_id: chatId,
      ai_response: aiResp
    },
    _meta: {
      source: 'NN_03-B_Pipeline_Agent',
      timestamp: new Date().toISOString(),
      debug_topic: $('Parse: get_services').first().json.query,
      version: '2.1.0'
    }
  }
}];

// Build Prompt: get_services
const sql = $('Analyze Resolve').first().json.sql_context || {};
const ragDocs = $json.data?.documents || [];
const userText = $('Input_Clean').first().json.text;

let prompt = `Eres la recepcionista amable de Booking Titanium. Responde la duda del usuario.\n\n`;

if (sql.resolved) {
  prompt += `### INFORMACIÓN OFICIAL DEL SERVICIO\n`;
  prompt += `- Nombre: ${sql.service_name}\n`;
  prompt += `- Precio: ${sql.price || 'Consultar'} ${sql.currency || 'USD'}\n\n`;
}

if (ragDocs.length > 0) {
  prompt += `### DOCUMENTACIÓN ADICIONAL\n`;
  prompt += JSON.stringify(ragDocs) + `\n\n`;
}

prompt += `### MENSAJE DEL USUARIO\n${userText}\n\n`;
prompt += `INSTRUCCIÓN: Responde de forma breve (máximo 3 oraciones), profesional y amable en ESPAÑOL.`;

return [{ json: { prompt } }];
